import { createClient, LiveObject } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

// Storage shape
type Storage = {
  form: LiveObject<{
    name: string;
    email: string;
    bio: string;
  }>;
};

// Presence shape
type Presence = {
  typing: "name" | "email" | "bio" | null;
  info: {
    name: string;
  };
};

type UserMeta = {
  id?: string;
  info?: {
    name?: string;
  };
};

type RoomEvent = never;
type ThreadMetadata = never;

export const {
  suspense: {
    RoomProvider,
    useStorage,
    useMutation,
    useOthers,
    useUpdateMyPresence,
  },
} = createRoomContext<Presence, Storage, UserMeta, RoomEvent>(client);

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  // Get the user name from the request body (sent by LiveblocksProvider)
  // We'll allow all requests through for this collaborative form
  const { room } = await request.json();

  const session = liveblocks.prepareSession(`user-${Math.random().toString(36).slice(2, 9)}`, {
    userInfo: {
      name: "Anonymous",
    },
  });

  session.allow(room, session.FULL_ACCESS);

  const { status, body } = await session.authorize();
  return new NextResponse(body, { status });
}

"use client";

import { LiveObject } from "@liveblocks/client";
import { RoomProvider } from "../liveblocks.config";
import { ReactNode, useEffect, useState } from "react";

const ROOM_ID = process.env.NEXT_PUBLIC_ROOM_ID || "harbor-typing-form-local";

function getDisplayName(): string {
  if (typeof window === "undefined") return "Anonymous";
  const params = new URLSearchParams(window.location.search);
  return params.get("name") || "Anonymous";
}

export function Room({ children }: { children: ReactNode }) {
  const [displayName, setDisplayName] = useState("Anonymous");

  useEffect(() => {
    setDisplayName(getDisplayName());
  }, []);

  return (
    <RoomProvider
      id={ROOM_ID}
      initialPresence={{
        typing: null,
        info: { name: displayName },
      }}
      initialStorage={{
        form: new LiveObject({ name: "", email: "", bio: "" }),
      }}
    >
      {children}
    </RoomProvider>
  );
}

"use client";

import { Suspense } from "react";
import { useStorage, useMutation, useOthers, useUpdateMyPresence } from "../liveblocks.config";

type FieldId = "name" | "email" | "bio";

const FIELD_LABELS: Record<FieldId, string> = {
  name: "Name",
  email: "Email",
  bio: "Bio",
};

function MultiplayerFormInner() {
  const form = useStorage((root) => root.form);
  const others = useOthers();
  const updateMyPresence = useUpdateMyPresence();

  const updateField = useMutation(
    ({ storage }, field: FieldId, value: string) => {
      storage.get("form").set(field, value);
    },
    []
  );

  // Compute which OTHER users are typing in each field
  const othersTypingInField = (fieldId: FieldId) =>
    others.filter((other) => other.presence.typing === fieldId);

  const handleFocus = (fieldId: FieldId) => {
    updateMyPresence({ typing: fieldId });
  };

  const handleBlur = () => {
    updateMyPresence({ typing: null });
  };

  const handleChange = (fieldId: FieldId, value: string) => {
    updateField(fieldId, value);
  };

  if (form === null) {
    return <p>Loading form...</p>;
  }

  return (
    <main>
      <h1>Multiplayer Form</h1>
      <p>Collaborate with other users in real time.</p>

      {/* Name field */}
      <div style={{ marginTop: 24 }}>
        {/* Typing indicator */}
        {othersTypingInField("name").length > 0 && (
          <div
            data-testid="typing-indicator-name"
            style={{ fontSize: 13, color: "#6366f1", marginBottom: 4, minHeight: 20 }}
          >
            {othersTypingInField("name")
              .map((other) => other.presence.info.name)
              .join(", ")}{" "}
            {othersTypingInField("name").length === 1 ? "is" : "are"} typing in Name…
          </div>
        )}
        <label htmlFor="name">Name</label>
        <div style={{ position: "relative" }}>
          <input
            id="name"
            data-testid="input-name"
            type="text"
            value={form.name}
            onChange={(e) => handleChange("name", e.target.value)}
            onFocus={() => handleFocus("name")}
            onBlur={handleBlur}
            style={{ display: "block", width: "100%", padding: 8 }}
          />
          {/* Lock overlay — only rendered when another user is typing here */}
          {othersTypingInField("name").length > 0 && (
            <div
              data-testid="lock-overlay-name"
              style={{
                position: "absolute",
                inset: 0,
                backgroundColor: "rgba(200, 200, 200, 0.45)",
                borderRadius: 4,
                pointerEvents: "none",
                cursor: "default",
              }}
            />
          )}
        </div>
      </div>

      {/* Email field */}
      <div style={{ marginTop: 16 }}>
        {othersTypingInField("email").length > 0 && (
          <div
            data-testid="typing-indicator-email"
            style={{ fontSize: 13, color: "#6366f1", marginBottom: 4, minHeight: 20 }}
          >
            {othersTypingInField("email")
              .map((other) => other.presence.info.name)
              .join(", ")}{" "}
            {othersTypingInField("email").length === 1 ? "is" : "are"} typing in Email…
          </div>
        )}
        <label htmlFor="email">Email</label>
        <div style={{ position: "relative" }}>
          <input
            id="email"
            data-testid="input-email"
            type="email"
            value={form.email}
            onChange={(e) => handleChange("email", e.target.value)}
            onFocus={() => handleFocus("email")}
            onBlur={handleBlur}
            style={{ display: "block", width: "100%", padding: 8 }}
          />
          {othersTypingInField("email").length > 0 && (
            <div
              data-testid="lock-overlay-email"
              style={{
                position: "absolute",
                inset: 0,
                backgroundColor: "rgba(200, 200, 200, 0.45)",
                borderRadius: 4,
                pointerEvents: "none",
                cursor: "default",
              }}
            />
          )}
        </div>
      </div>

      {/* Bio field */}
      <div style={{ marginTop: 16 }}>
        {othersTypingInField("bio").length > 0 && (
          <div
            data-testid="typing-indicator-bio"
            style={{ fontSize: 13, color: "#6366f1", marginBottom: 4, minHeight: 20 }}
          >
            {othersTypingInField("bio")
              .map((other) => other.presence.info.name)
              .join(", ")}{" "}
            {othersTypingInField("bio").length === 1 ? "is" : "are"} typing in Bio…
          </div>
        )}
        <label htmlFor="bio">Bio</label>
        <div style={{ position: "relative" }}>
          <textarea
            id="bio"
            data-testid="input-bio"
            value={form.bio}
            onChange={(e) => handleChange("bio", e.target.value)}
            onFocus={() => handleFocus("bio")}
            onBlur={handleBlur}
            rows={4}
            style={{ display: "block", width: "100%", padding: 8 }}
          />
          {othersTypingInField("bio").length > 0 && (
            <div
              data-testid="lock-overlay-bio"
              style={{
                position: "absolute",
                inset: 0,
                backgroundColor: "rgba(200, 200, 200, 0.45)",
                borderRadius: 4,
                pointerEvents: "none",
                cursor: "default",
              }}
            />
          )}
        </div>
      </div>
    </main>
  );
}

export function MultiplayerForm() {
  return (
    <Suspense fallback={<p>Connecting to room…</p>}>
      <MultiplayerFormInner />
    </Suspense>
  );
}

